(()=>{document.addEventListener("DOMContentLoaded",()=>{let n=document.querySelector("#toggle-cortina"),o=document.querySelector(".cortina");n&&o&&n.addEventListener("click",()=>{o.classList.toggle("hidden")});let r=e=>{e.style.opacity=0,e.style.transition="opacity 1s ease-in",requestAnimationFrame(()=>{e.style.opacity=1})};document.querySelectorAll(".fade-in").forEach(r);let c=document.getElementById("blog-list");fetch("articulos/index.json").then(e=>e.json()).then(e=>{c.innerHTML="",e.forEach(t=>{c.innerHTML+=`
                <div class="articulo">
                    <h2>${t.title}</h2>
                    <p>${t.description||""}</p>
                    <a href="${t.url}">Leer m\xE1s</a>
                    <small>Fecha: ${t.date}</small>
                </div>
            `}),console.log("Art\xEDculos cargados:",e.length)}).catch(e=>console.error("Error al cargar art\xEDculos:",e))});})();
